// Helper: calculate scaled material requirements for any quantity
// For kg-output items: scale by target_kg / outputQty
// For pcs-output items: scale by target_pcs / outputQty
// For loaf-output items: scale by target_loaves / outputQty
export function calculateMaterials(
  itemId: string,
  quantity: number,
  unit: 'kg' | 'pcs' | 'loaf'
): { material: string; quantity: number; unit: string }[] {
  const recipe = RECIPE_DEFINITIONS[itemId];
  if (!recipe || !recipe.outputQty || quantity <= 0) return [];
  const scaleFactor = quantity / recipe.outputQty;
  return recipe.materials.map(m => ({
    material: m.material,
    quantity: parseFloat((m.qty * scaleFactor).toFixed(4)),
    unit: m.unit,
  }));
}